const currentData = $('Fetch Current Prices').all();
const initData = $('Initialize Monitoring Session').first().json;

// Transform current prices to standard format
const products = [];
for (const item of currentData) {
  const priceData = item.json.products || [item.json];
  for (const product of (Array.isArray(priceData) ? priceData : [priceData])) {
    products.push({
      productId: product.id || product.sku || 'unknown',
      productName: product.name || product.title || 'Unknown Product',
      competitor: product.competitor || 'Unknown',
      currentPrice: parseFloat(product.price) || 0,
      currency: product.currency || 'USD',
      category: product.category || 'General',
      url: product.url || '',
      fetchedAt: initData.checkTimestamp
    });
  }
}

return products.map(p => ({ json: p }));

const previousData = $('Fetch Previous Prices').all();

// Transform previous prices to standard format
const products = previousData.map(item => ({
  productId: item.json.productId || item.json['Product ID'] || 'unknown',
  productName: item.json.productName || item.json['Product Name'] || 'Unknown',
  competitor: item.json.competitor || item.json['Competitor'] || 'Unknown',
  previousPrice: parseFloat(item.json.currentPrice || item.json['Price'] || 0),
  currency: item.json.currency || item.json['Currency'] || 'USD',
  category: item.json.category || item.json['Category'] || 'General',
  lastUpdated: item.json.fetchedAt || item.json['Last Updated'] || ''
}));

return products.map(p => ({ json: p }));

// Process removed products (In A only - was in previous, not in current)
const items = $input.all();

return items.map(item => ({
  json: {
    ...item.json,
    changeType: 'REMOVED',
    changePercent: -100,
    alertLevel: 'routine',
    analysis: 'Product no longer available from competitor'
  }
}));

// Process unchanged products (Same)
const items = $input.all();

return items.map(item => ({
  json: {
    ...item.json,
    changeType: 'UNCHANGED',
    changePercent: 0,
    alertLevel: 'none',
    analysis: 'Price stable'
  }
}));

// Process changed products (Different) - key analysis
const items = $input.all();

return items.map(item => {
  const d = item.json;
  const prevPrice = d.input1?.previousPrice || d.previousPrice || 0;
  const currPrice = d.input2?.currentPrice || d.currentPrice || 0;
  const changePercent = prevPrice > 0 ? ((currPrice - prevPrice) / prevPrice * 100) : 0;
  const absChange = Math.abs(changePercent);

  let alertLevel = 'none';
  if (absChange >= 10) alertLevel = 'urgent';
  else if (absChange >= 5) alertLevel = 'routine';

  return {
    json: {
      productId: d.input1?.productId || d.input2?.productId || d.productId,
      productName: d.input2?.productName || d.input1?.productName || d.productName,
      competitor: d.input2?.competitor || d.input1?.competitor || d.competitor,
      previousPrice: prevPrice,
      currentPrice: currPrice,
      currency: d.input2?.currency || d.input1?.currency || 'USD',
      category: d.input2?.category || d.input1?.category || 'General',
      changeType: changePercent > 0 ? 'PRICE_INCREASE' : 'PRICE_DECREASE',
      changePercent: Math.round(changePercent * 100) / 100,
      alertLevel: alertLevel
    }
  };
});

// Process new products (In B only - in current, not in previous)
const items = $input.all();

return items.map(item => ({
  json: {
    ...item.json,
    changeType: 'NEW_PRODUCT',
    changePercent: null,
    alertLevel: 'routine',
    analysis: 'New product detected in competitor catalog'
  }
}));

