parameters.jsCode:
const priceData = $input.first().json;
const aiOutput = priceData.output || '{}';

let aiAnalysis = {};
try {
  const jsonMatch = aiOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    aiAnalysis = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  aiAnalysis = {
    impactAssessment: 'Unable to analyze - manual review recommended',
    recommendedAction: 'hold',
    urgencyJustification: 'AI analysis unavailable'
  };
}

// Get original price data from the filter output
const originalData = $('Filter Significant Changes').first().json;

return [{
  json: {
    ...originalData,
    aiAnalysis: aiAnalysis,
    analyzedAt: new Date().toISOString()
  }
}];

